import type { FlatternOption } from '../SelectOverlay';
import type { SelectContextType } from './SelectContext';
import type { InternalSelectOptionConfig, SelectValue } from '../internal.interface';
export type SelectAllParams<V extends SelectValue, OP extends InternalSelectOptionConfig<V>> = {
    valueSet: Set<V>;
    flattenOptions: FlatternOption<V>[];
    set: SelectContextType<V, OP>['set'];
};
/**
 *  全选的相关逻辑：
 *  1. 如果没有 options: unChecked, disabled
 *  2. disabled & unChecked 的option, 不参与数量统计
 *  3. 如果 options 全为 disabled 态， 全选操作禁用，如果里面有 checked 态 option, 全选选中
 *
 *  最终状态：
 *  disabled:
 *    选项全部为 disabled 或 选项个数为 0
 *  checked:
 *    选中的个数不为0， 并且所有可选的选项已选
 *  unChecked
 *    其他情况
 *  总数：
 *    可选选项及disabled 但选中的个数
 */
export default function useSelectAll<V extends SelectValue, OP extends InternalSelectOptionConfig<V>>(args: SelectAllParams<V, OP>): {
    hasSelectedAll: boolean;
    onToggleSelectAll: () => void;
    isSelectAllDisabled: boolean;
    selectAllCount: number;
};
